fn tp_iii_to_md(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 @export {
    let header_len : u64 = 7u64
    let footer_len : u64 = 5u64
    /* Subtraction-form overflow guard: dst_cap - 12 >= src_len required.
     * Addition form (header+src_len+footer > dst_cap) wraps when src_len near MAXU64. */
    if dst_cap < 12u64 { return 0u64 }
    if src_len > dst_cap - 12u64 { return 0u64 }
    let total : u64 = header_len + src_len + footer_len
    /* Write header */
    let mut i : u32 = 0u32
    while i < 7u32 {
        tp_iii_to_md_emit_byte(dst_buf, (i as u64) & 0xFFu64, TP_MD_HEADER[i])
        i = i + 1u32
    }
    /* Copy source */
    let mut j : u64 = 0u64
    while j < src_len {
        let bp : *u8 = (src + j) as *u8
        tp_iii_to_md_emit_byte(dst_buf, header_len + j, bp[0u64])
        j = j + 1u64
    }
    /* Write footer */
    let mut k : u32 = 0u32
    while k < 5u32 {
        tp_iii_to_md_emit_byte(dst_buf, header_len + src_len + ((k as u64) & 0xFFu64), TP_MD_FOOTER[k])
        k = k + 1u32
    }
    return total
}

fn tp_iii_to_ast_bin(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 @export {
    /* Subtraction-form: 16 + src_len > dst_cap wraps when src_len near MAXU64. */
    if dst_cap < 16u64 { return 0u64 }
    if src_len > dst_cap - 16u64 { return 0u64 }
    /* Magic (8 bytes) */
    let mut i : u32 = 0u32
    while i < 8u32 {
        tp_ast_emit(dst_buf, (i as u64) & 0xFFu64, TP_AST_MAGIC[i])
        i = i + 1u32
    }
    /* src_len LE u64 (8 bytes) */
    let mut k : u32 = 0u32
    while k < 8u32 {
        let b : u8 = ((src_len >> ((k & 0x7u32) * 8u32)) & 0xFFu64) as u8
        tp_ast_emit(dst_buf, 8u64 + ((k as u64) & 0xFu64), b)
        k = k + 1u32
    }
    /* Body */
    let mut j : u64 = 0u64
    while j < src_len {
        let bp : *u8 = (src + j) as *u8
        tp_ast_emit(dst_buf, 16u64 + j, bp[0u64])
        j = j + 1u64
    }
    return 16u64 + src_len
}

fn tp_babel_text_back(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 @export {
    let mut in_off : u64 = 0u64
    let mut out_off : u64 = 0u64
    /* Subtraction-form: dst_cap < src_len + 4 wraps when src_len near MAXU64. */
    if dst_cap < 4u64 { return 0u64 }
    if src_len > dst_cap - 4u64 { return 0u64 }
    /* Open brace */
    tp_btb_emit(dst_buf, out_off, 123u8)
    out_off = out_off + 1u64
    let mut depth : u32 = 0u32
    while in_off < src_len {
        let bp : *u8 = (src + in_off) as *u8
        let c : u8 = bp[0u64]
        if c == 123u8 { depth = depth + 1u32 }
        if c == 125u8 { depth = depth - 1u32 }
        if c == 10u8 {
            if depth == 0u32 {
                tp_btb_emit(dst_buf, out_off, 44u8)
                out_off = out_off + 1u64
            }
            if depth != 0u32 {
                tp_btb_emit(dst_buf, out_off, c)
                out_off = out_off + 1u64
            }
        }
        if c != 10u8 {
            tp_btb_emit(dst_buf, out_off, c)
            out_off = out_off + 1u64
        }
        in_off = in_off + 1u64
    }
    /* Close brace */
    tp_btb_emit(dst_buf, out_off, 125u8)
    out_off = out_off + 1u64
    return out_off
}

fn tp_babel_json_cbor(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 @export {
    let mut hdr_len : u64 = 1u64
    /* CBOR major type 2 (byte string) length encoding:
     *   0x40..0x57: length 0..23 (1 byte total)
     *   0x58 NN: 24-255 (2 bytes header)
     *   0x59 NN NN: 256-65535 (3 bytes header)
     *   0x5A NN NN NN NN: u32 length (5 bytes header)
     *   0x5B u64 length (9 bytes header)
     */
    if src_len < 24u64 {
        hdr_len = 1u64
    }
    if src_len >= 24u64 {
        if src_len < 256u64 { hdr_len = 2u64 }
    }
    if src_len >= 256u64 {
        if src_len < 65536u64 { hdr_len = 3u64 }
    }
    if src_len >= 65536u64 {
        if src_len < 4294967296u64 { hdr_len = 5u64 }
    }
    if src_len >= 4294967296u64 { hdr_len = 9u64 }
    /* Subtraction-form: hdr_len + src_len overflows when src_len near MAXU64.
     * hdr_len <= 9, so: if src_len > dst_cap - hdr_len, refuse. */
    if dst_cap < hdr_len { return 0u64 }
    if src_len > dst_cap - hdr_len { return 0u64 }
    let total : u64 = hdr_len + src_len
    if hdr_len == 1u64 {
        tp_bjc_emit(dst_buf, 0u64, 0x40u8 | ((src_len & 0x1Fu64) as u8))
    }
    if hdr_len == 2u64 {
        tp_bjc_emit(dst_buf, 0u64, 0x58u8)
        tp_bjc_emit(dst_buf, 1u64, (src_len & 0xFFu64) as u8)
    }
    if hdr_len == 3u64 {
        tp_bjc_emit(dst_buf, 0u64, 0x59u8)
        tp_bjc_emit(dst_buf, 1u64, ((src_len >> 8u64) & 0xFFu64) as u8)
        tp_bjc_emit(dst_buf, 2u64, (src_len & 0xFFu64) as u8)
    }
    if hdr_len == 5u64 {
        tp_bjc_emit(dst_buf, 0u64, 0x5Au8)
        tp_bjc_emit(dst_buf, 1u64, ((src_len >> 24u64) & 0xFFu64) as u8)
        tp_bjc_emit(dst_buf, 2u64, ((src_len >> 16u64) & 0xFFu64) as u8)
        tp_bjc_emit(dst_buf, 3u64, ((src_len >> 8u64) & 0xFFu64) as u8)
        tp_bjc_emit(dst_buf, 4u64, (src_len & 0xFFu64) as u8)
    }
    if hdr_len == 9u64 {
        tp_bjc_emit(dst_buf, 0u64, 0x5Bu8)
        let mut k : u32 = 0u32
        while k < 8u32 {
            let shift : u64 = ((7u64 - ((k as u64) & 0x7u64)) * 8u64)
            tp_bjc_emit(dst_buf, 1u64 + ((k as u64) & 0xFu64), ((src_len >> shift) & 0xFFu64) as u8)
            k = k + 1u32
        }
    }
    /* Copy payload */
    let mut j : u64 = 0u64
    while j < src_len {
        let bp : *u8 = (src + j) as *u8
        tp_bjc_emit(dst_buf, hdr_len + j, bp[0u64])
        j = j + 1u64
    }
    return total
}

fn tp_iii_to_babel_json(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 @export {
    /* Conservative size estimate: prefix(83) + 4*ceil(src_len/3) + suffix(2).
     * Overflow analysis: src_len+2 wraps near MAXU64; then multiply wraps.
     * Subtraction-form guard: if src_len > (dst_cap - 89) / 4 * 3, refuse.
     * (89 = 83 prefix + 4 max b64 padding + 2 suffix; /4*3 gives max src bytes.)
     * Check dst_cap >= 89 first to avoid underflow in dst_cap - 89. */
    if dst_cap < 89u64 { return 0u64 }
    let body_cap : u64 = dst_cap - 89u64
    /* body_cap/4 * 3 = max src bytes that fit. If src_len > that, refuse. */
    if src_len > (body_cap / 4u64) * 3u64 { return 0u64 }
    let est : u64 = 83u64 + 4u64 * ((src_len + 2u64) / 3u64) + 4u64
    if est > dst_cap { return 0u64 }
    let mut off : u64 = 0u64
    /* Prefix (83 bytes used) */
    let mut p : u32 = 0u32
    while p < 83u32 {
        tp_bj_emit(dst_buf, off, TP_BJ_PRE[p])
        off = off + 1u64
        p = p + 1u32
    }
    /* Base64 body */
    let mut j : u64 = 0u64
    while j + 3u64 <= src_len {
        let b0 : *u8 = (src + j) as *u8
        let b1 : *u8 = (src + j + 1u64) as *u8
        let b2 : *u8 = (src + j + 2u64) as *u8
        tp_bj_b64_triplet(dst_buf, off, b0[0u64], b1[0u64], b2[0u64])
        off = off + 4u64
        j = j + 3u64
    }
    /* Tail (1 or 2 leftover bytes with padding) */
    let rem : u64 = src_len - j
    if rem == 1u64 {
        let b0 : *u8 = (src + j) as *u8
        tp_bj_b64_triplet(dst_buf, off, b0[0u64], 0u8, 0u8)
        tp_bj_emit(dst_buf, off + 2u64, 61u8)   /* '=' */
        tp_bj_emit(dst_buf, off + 3u64, 61u8)
        off = off + 4u64
    }
    if rem == 2u64 {
        let b0 : *u8 = (src + j) as *u8
        let b1 : *u8 = (src + j + 1u64) as *u8
        tp_bj_b64_triplet(dst_buf, off, b0[0u64], b1[0u64], 0u8)
        tp_bj_emit(dst_buf, off + 3u64, 61u8)
        off = off + 4u64
    }
    /* Suffix */
    tp_bj_emit(dst_buf, off, TP_BJ_POST[0])
    tp_bj_emit(dst_buf, off + 1u64, TP_BJ_POST[1])
    off = off + 2u64
    return off
}

fn tp_ast_to_babel_json(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 @export {
    /* Same overflow pattern as tp_iii_to_babel_json: src_len+2 wraps first.
     * Overhead = 79 prefix + 4 max padding + 2 suffix = 85.
     * Subtraction-form: if dst_cap < 85 refuse; if src_len > (dst_cap-85)/4*3 refuse. */
    if dst_cap < 85u64 { return 0u64 }
    let body_cap : u64 = dst_cap - 85u64
    if src_len > (body_cap / 4u64) * 3u64 { return 0u64 }
    let est : u64 = 79u64 + 4u64 * ((src_len + 2u64) / 3u64) + 4u64
    if est > dst_cap { return 0u64 }
    let mut off : u64 = 0u64
    let mut p : u32 = 0u32
    while p < 79u32 {
        tp_atbj_emit(dst_buf, off, TP_ATBJ_PRE[p])
        off = off + 1u64
        p = p + 1u32
    }
    let mut j : u64 = 0u64
    while j + 3u64 <= src_len {
        let b0 : *u8 = (src + j) as *u8
        let b1 : *u8 = (src + j + 1u64) as *u8
        let b2 : *u8 = (src + j + 2u64) as *u8
        tp_atbj_b64_triplet(dst_buf, off, b0[0u64], b1[0u64], b2[0u64])
        off = off + 4u64
        j = j + 3u64
    }
    let rem : u64 = src_len - j
    if rem == 1u64 {
        let b0 : *u8 = (src + j) as *u8
        tp_atbj_b64_triplet(dst_buf, off, b0[0u64], 0u8, 0u8)
        tp_atbj_emit(dst_buf, off + 2u64, 61u8)
        tp_atbj_emit(dst_buf, off + 3u64, 61u8)
        off = off + 4u64
    }
    if rem == 2u64 {
        let b0 : *u8 = (src + j) as *u8
        let b1 : *u8 = (src + j + 1u64) as *u8
        tp_atbj_b64_triplet(dst_buf, off, b0[0u64], b1[0u64], 0u8)
        tp_atbj_emit(dst_buf, off + 3u64, 61u8)
        off = off + 4u64
    }
    tp_atbj_emit(dst_buf, off, TP_ATBJ_POST[0])
    tp_atbj_emit(dst_buf, off + 1u64, TP_ATBJ_POST[1])
    off = off + 2u64
    return off
}

fn tp_table_call(idx: u32, src: u64, src_len: u64, dst: u64, dst_cap: u64) -> u64 @export {
    let f : u64 = tp_table_get_fn(idx)
    if f == 0u64 { return 0u64 }
    /* Indirect call via u64 fn-pointer (per fold.iii pattern).
     * dst_cap is now caller-supplied; the previous fabricated 1048576u64 was
     * a lie that made codec overflow guards meaningless. */
    return f(src, src_len, dst, dst_cap)
}

/* 1023_tp_transpiler_bounds.iii -- KAT for tp-transpiler-bounds (backlog item #15 CRITICAL).
 *
 * Proves two fix layers:
 * L1: subtraction-form overflow guards in 6 Bucket-A codecs.
 *     Negative case: src_len = 0xFFFFFFFFFFFFFFECu64 (= MAXU64-19) with a 16-byte
 *     dst forces each codec to return 0 (refuses to write). Without the fix the
 *     addition-form check wraps below dst_cap and the codec would run to a huge
 *     src_len, causing OOB memory access.
 * L2: tp_table_call now takes dst_cap; the old fabricated 1 MiB is gone.
 *     Negative case: call tp_table_call with a 1-byte dst_cap and assert it
 *     returns 0 (codec refuses), not a 1-MiB write past a 1-byte buffer.
 *
 * rc 99 = all checks pass.
 */
module corpus_1023

extern @abi(c-msvc-x64) fn tp_iii_to_md(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 from "tp_iii_to_md.iii"
extern @abi(c-msvc-x64) fn tp_iii_to_ast_bin(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 from "tp_iii_to_ast_bin.iii"
extern @abi(c-msvc-x64) fn tp_babel_text_back(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 from "tp_babel_text_back.iii"
extern @abi(c-msvc-x64) fn tp_babel_json_cbor(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 from "tp_babel_json_cbor.iii"
extern @abi(c-msvc-x64) fn tp_iii_to_babel_json(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 from "tp_iii_to_babel_json.iii"
extern @abi(c-msvc-x64) fn tp_ast_to_babel_json(src: u64, src_len: u64, dst_buf: u64, dst_cap: u64) -> u64 from "tp_ast_to_babel_json.iii"
extern @abi(c-msvc-x64) fn tp_table_call(idx: u32, src: u64, src_len: u64, dst: u64, dst_cap: u64) -> u64 from "transform_patterns.iii"

/* A real 128-byte output buffer for positive-arm round-trips. */
var TP_DST : [u8; 128]
/* A tiny 16-byte buffer used as a too-small destination for negative cases. */
var TP_TINY : [u8; 16]
/* A 4-byte source with known content. */
var TP_SRC4 : [u8; 4]

fn main() -> u64 {
    /* --- Positive arms: real inputs fit in a real buffer ------------------- */
    /* Fill TP_SRC4 with 4 recognisable bytes. */
    let ps : *u8 = (&TP_SRC4 as u64) as *u8
    ps[0u64] = 1u8
    ps[1u64] = 2u8
    ps[2u64] = 3u8
    ps[3u64] = 4u8

    /* tp_iii_to_md: 4-byte src, 128-byte dst must produce 7+4+5=16 bytes. */
    let md_len : u64 = tp_iii_to_md(&TP_SRC4 as u64, 4u64, &TP_DST as u64, 128u64)
    if md_len != 16u64 { return 1u64 }

    /* tp_iii_to_ast_bin: 4-byte src => 16+4=20 bytes. */
    let ast_len : u64 = tp_iii_to_ast_bin(&TP_SRC4 as u64, 4u64, &TP_DST as u64, 128u64)
    if ast_len != 20u64 { return 2u64 }

    /* tp_babel_text_back: wrap '{' + 4 bytes + '}' = 6 bytes minimum. */
    let btb_len : u64 = tp_babel_text_back(&TP_SRC4 as u64, 4u64, &TP_DST as u64, 128u64)
    if btb_len == 0u64 { return 3u64 }

    /* tp_babel_json_cbor: 4-byte input => hdr(1) + 4 = 5 bytes. */
    let cbrlen : u64 = tp_babel_json_cbor(&TP_SRC4 as u64, 4u64, &TP_DST as u64, 128u64)
    if cbrlen != 5u64 { return 4u64 }

    /* tp_iii_to_babel_json: 4 bytes => 83 + ceil(4/3)*4 + 2 = 91 bytes. */
    let bjlen : u64 = tp_iii_to_babel_json(&TP_SRC4 as u64, 4u64, &TP_DST as u64, 128u64)
    if bjlen == 0u64 { return 5u64 }

    /* tp_ast_to_babel_json: same structure. */
    let abjlen : u64 = tp_ast_to_babel_json(&TP_SRC4 as u64, 4u64, &TP_DST as u64, 128u64)
    if abjlen == 0u64 { return 6u64 }

    /* --- L1 negative: overflow-wrapped src_len with tiny dst forces 0 ------ */
    /* src_len = MAXU64 - 19 = 0xFFFFFFFFFFFFFFECu64.
     * Addition form: 7 + MAXU64-19 + 5 = MAXU64-7 wraps to 0xFFFFFFFFFFFFFFF8
     * which for any dst_cap < that passes the old check, then the copy loop
     * would run MAXU64-19 iterations.  Subtraction form refuses immediately. */
    let big : u64 = 0xFFFFFFFFFFFFFFECu64
    if tp_iii_to_md(&TP_SRC4 as u64, big, &TP_TINY as u64, 16u64) != 0u64 { return 11u64 }
    if tp_iii_to_ast_bin(&TP_SRC4 as u64, big, &TP_TINY as u64, 16u64) != 0u64 { return 12u64 }
    if tp_babel_text_back(&TP_SRC4 as u64, big, &TP_TINY as u64, 16u64) != 0u64 { return 13u64 }
    if tp_babel_json_cbor(&TP_SRC4 as u64, big, &TP_TINY as u64, 16u64) != 0u64 { return 14u64 }
    if tp_iii_to_babel_json(&TP_SRC4 as u64, big, &TP_TINY as u64, 16u64) != 0u64 { return 15u64 }
    if tp_ast_to_babel_json(&TP_SRC4 as u64, big, &TP_TINY as u64, 16u64) != 0u64 { return 16u64 }

    /* --- L2 negative: tp_table_call with honest 1-byte dst_cap refuses ------ */
    /* Slot 11 in the table (0-based) = slot 29 in the pattern table = tp_iii_to_c99
     * (registered at _tx_register(28,...) -> tp_table index 28-18=10).
     * We call idx=10 (tp_iii_to_c99) with 4-byte src, 4-byte dst_cap.
     * tp_iii_to_c99 needs >= 33+1 bytes for header alone, so 4 is too small.
     * With the old fabricated 1MiB cap the codec proceeds to write.
     * With the new caller-supplied cap=4 the codec's first guard fires -> 0. */
    if tp_table_call(10u32, &TP_SRC4 as u64, 4u64, &TP_TINY as u64, 4u64) != 0u64 { return 21u64 }

    /* L2 positive: supply a real 128-byte cap, same idx, codec must succeed. */
    let c99len : u64 = tp_table_call(10u32, &TP_SRC4 as u64, 4u64, &TP_DST as u64, 128u64)
    if c99len == 0u64 { return 22u64 }

    return 99u64
}
